from itertools import combinations
class Solution:
    def maxScore(self, nums1, nums2, k):
        n = len(nums1)
        best = 0
        for combo in combinations(range(n), k):
            s = sum(nums1[i] for i in combo)
            m = min(nums2[i] for i in combo)
            best = max(best, s * m)
        return best

