import heapq
class Solution:
    def maxScore(self, nums1, nums2, k):
        n = len(nums1)
        order = sorted(range(n), key=lambda i: -nums2[i])
        heap = []
        s = 0
        best = 0
        for idx in order:
            heapq.heappush(heap, nums1[idx])
            s += nums1[idx]
            if len(heap) > k:
                s -= heapq.heappop(heap)
            if len(heap) == k:
                best = max(best, s * nums2[idx])
        return best

